export type TokenRecord = {
  id: string;
  userId: string;
  name: string;
  secretHash: string;
  revoked: boolean;
};

export type LocalRegistryState = {
  users: Array<{ id: string; handle: string; admin?: boolean }>;
  tokens: TokenRecord[];
  artifacts: ArtifactVersion[];
};

export type SeedObjectPayload = {
  ref: ObjectRef;
  payload: string | Uint8Array;
};

export function createLocalRegistryState(): LocalRegistryState {
  return {
    users: [
      { id: 'user_local', handle: 'local', admin: true },
      { id: 'user_member', handle: 'member', admin: false },
    ],
    tokens: [],
    artifacts: [],
  };
}

