const rawSeedArtifacts: ArtifactVersion[] = [
  ...Object.values(seedDefinitions).map<ArtifactVersion>(definition => ({
    id: artifactVersionId(definition.kind, definition.owner, definition.name, definition.version),
    kind: definition.kind,
    owner: definition.owner,
    name: definition.name,
    version: definition.version,
    publishedAt: 'publishedAt' in definition ? definition.publishedAt : undefined,
    readme: 'readme' in definition ? definition.readme : '',
    dependencies: 'dependencies' in definition ? [...definition.dependencies] : [],
    resolvedPins:
      'resolvedPins' in definition
        ? definition.resolvedPins.map(pin => ({ ...pin, owner: pin.owner ?? definition.owner }))
        : [],
    artifactObjects: artifactObjectsFor(definition),
    scriptOnly: 'scriptOnly' in definition ? definition.scriptOnly : undefined,
    disabled: false,
    moderationState: 'active' as const,
    downloads: 'downloads' in definition && typeof definition.downloads === 'number' ? definition.downloads : 0,
    likes: 'likes' in definition && typeof definition.likes === 'number' ? definition.likes : 0,
  })),
];

type SeedPayloadPart = {
  key: string;
  sha256: string;
  size: number;
  payloadBase64: string;
  binary?: boolean;
};

function seedPart(key: string, sha256: string, size: number, payloadBase64: string, binary = false): SeedPayloadPart {
  return { key, sha256, size, payloadBase64, binary };
}

function seedTemplateDefinition(
  name: string,
  readme: string,
  description: string,
  payloads: {
    dependencies?: ArtifactVersion['dependencies'];
    manifest: SeedPayloadPart;
    readme?: SeedPayloadPart;
    bundle: SeedPayloadPart;
    archive: SeedPayloadPart;
  },
) {
  return seedFolderDefinition('template', name, readme, description, payloads);
}

function seedTemplateGroupDefinition(
  name: string,
  readme: string,
  description: string,
  payloads: {
    dependencies?: ArtifactVersion['dependencies'];
    manifest: SeedPayloadPart;
    readme?: SeedPayloadPart;
    bundle: SeedPayloadPart;
    archive: SeedPayloadPart;
  },
) {
  return seedFolderDefinition('template-group', name, readme, description, payloads);
}

function seedFolderDefinition(
  kind: 'template' | 'template-group',
  name: string,
  readme: string,
  description: string,
  payloads: {
    dependencies?: ArtifactVersion['dependencies'];
    manifest: SeedPayloadPart;
    readme?: SeedPayloadPart;
    bundle: SeedPayloadPart;
    archive: SeedPayloadPart;
  },
) {
  const dependencies = payloads.dependencies ?? [{ kind: 'processor' as const, owner: 'cyanprint', name: 'default' }];
  return {
    kind,
    owner: 'cyanprint',
    name,
    version: '4',
    publishedAt: '2026-02-23T00:00:00.000Z',
    readme,
    scriptOnly: false,
    dependencies,
    resolvedPins: dependencies.map(pin => ({
      kind: pin.kind,
      owner: pin.owner,
      name: pin.name,
      version: pin.version ?? '4',
      integrity: 'metadata-only-seed',
    })),
    payloads: {
      manifest: payloads.manifest,
      ...(payloads.readme ? { readme: payloads.readme } : {}),
      bundle: payloads.bundle,
      archive: payloads.archive,
    },
    description,
  };
}

function seedRuntimeDefinition(
  kind: 'processor' | 'plugin' | 'resolver',
  name: string,
  readme: string,
  payloads: {
    manifestSha: string;
    manifestSize: number;
    manifestBase64: string;
    readmeSha: string;
    readmeSize: number;
    readmeBase64: string;
    bundleSha: string;
    bundleSize: number;
    bundleBase64: string;
  },
) {
  return {
    kind,
    owner: 'cyanprint',
    name,
    version: '4',
    publishedAt: '2026-02-23T00:00:00.000Z',
    readme,
    payloads: {
      manifest: {
        key: `${kind}/cyanprint/${name}/4/manifest.yaml`,
        sha256: payloads.manifestSha,
        size: payloads.manifestSize,
        payloadBase64: payloads.manifestBase64,
      },
      readme: {
        key: `${kind}/cyanprint/${name}/4/readme.md`,
        sha256: payloads.readmeSha,
        size: payloads.readmeSize,
        payloadBase64: payloads.readmeBase64,
      },
      bundle: {
        key: `${kind}/cyanprint/${name}/4/bundle.js`,
        sha256: payloads.bundleSha,
        size: payloads.bundleSize,
        payloadBase64: payloads.bundleBase64,
      },
    },
  };
}

function artifactObjectsFor(definition: {
  payloads: { manifest: SeedPayloadPart; readme?: SeedPayloadPart; bundle: SeedPayloadPart; archive?: SeedPayloadPart };
}): ArtifactObjects {
  return {
    manifest: objectRef(definition.payloads.manifest),
    ...(definition.payloads.readme ? { readme: objectRef(definition.payloads.readme) } : {}),
    bundle: objectRef(definition.payloads.bundle),
    ...(definition.payloads.archive ? { archive: objectRef(definition.payloads.archive) } : {}),
  };
}

function objectRef(part: SeedPayloadPart): ObjectRef {
  return {
    bucket: 'cyanprint-local-r2',
    key: part.key,
    sha256: part.sha256,
    size: part.size,
  };
}

function decodeBase64(part: SeedPayloadPart): string | Uint8Array {
  const binary = atob(part.payloadBase64);
  const bytes = Uint8Array.from(binary, char => char.charCodeAt(0));
  if (part.binary) {
    return bytes;
  }
  return new TextDecoder().decode(bytes);
}

export const seedArtifacts: ArtifactVersion[] = rawSeedArtifacts.map(canonicalizeArtifact);

export const seedObjectPayloads: SeedObjectPayload[] = Object.values(seedDefinitions).flatMap(definition =>
  Object.values(definition.payloads).map(part => ({
    ref: objectRef(part),
    payload: decodeBase64(part),
  })),
);

export function upsertArtifact(state: LocalRegistryState, artifact: ArtifactVersion): void {
  const index = state.artifacts.findIndex(
    existing =>
      existing.kind === artifact.kind &&
      existing.owner === artifact.owner &&
      existing.name === artifact.name &&
      existing.version === artifact.version,
  );
  if (index >= 0) {
    state.artifacts[index] = artifact;
    return;
  }
  state.artifacts.push(artifact);
}

export function batchResolve(state: LocalRegistryState, request: BatchResolveRequest): BatchResolveResponse {
  const resolved: ArtifactVersion[] = [];
  const missing: BatchResolveResponse['missing'] = [];
  for (const ref of request.refs) {
    const owner = ref.owner ?? 'local';
    const matches = state.artifacts
      .filter(
        artifact =>
          artifact.kind === ref.kind &&
          artifact.owner === owner &&
          artifact.name === ref.name &&
          isActiveArtifact(artifact) &&
          (!ref.version || artifact.version === ref.version),
      )
      .sort((left, right) => compareVersionDesc(left.version, right.version));
    const match = matches[0];
    if (match) {
      resolved.push(match);
    } else if (
      !missing.some(
        item =>
          item.kind === ref.kind && item.owner === owner && item.name === ref.name && item.version === ref.version,
      )
    ) {
      missing.push({ ...ref, owner });
    }
  }
  return { resolved, missing };
}

export function isActiveArtifact(artifact: ArtifactVersion): boolean {
  return artifact.moderationState === 'active' && !artifact.disabled;
}

function compareVersionDesc(left: string, right: string): number {
  return right.localeCompare(left, undefined, { numeric: true, sensitivity: 'base' });
}

function canonicalizeArtifact(artifact: ArtifactVersion): ArtifactVersion {
  return {
    ...artifact,
    id: artifactVersionId(artifact.kind, artifact.owner, artifact.name, artifact.version),
    resolvedPins: artifact.resolvedPins.map(pin => {
      const target = rawSeedArtifacts.find(
        artifact =>
          artifact.kind === pin.kind &&
          artifact.owner === pin.owner &&
          artifact.name === pin.name &&
          artifact.version === pin.version,
      );
      return {
        ...pin,
        integrity:
          pin.integrity === 'metadata-only-seed'
            ? `${artifactVersionId(pin.kind, pin.owner, pin.name, pin.version)}-metadata`
            : pin.integrity,
        ...(target?.object || target?.artifactObjects
          ? {
              integrity: artifactIntegrity(target),
            }
          : {}),
      };
    }),
  };
}
